svg.script:
const lines = ["line1", "line2", "line3", "line4"];
const speeds = [150, 100, 80, 60]; // سرعات الكتابة بالملي ثانية
let lineIndex = 0;

function typeLine() {
  if (lineIndex >= lines.length) return;
  const currentId = lines[lineIndex];
  const speed = speeds[lineIndex];
  const textElement = document.getElementById(currentId);
  const text = textElement.textContent;
  textElement.textContent = ""; // مسح النص الأصلي
  let charIndex = 0;

  function typeChar() {
    if (charIndex < text.length) {
      textElement.textContent += text.charAt(charIndex);
      charIndex++;
      setTimeout(typeChar, speed);
    } else {
      // السطر اكتمل، انتقل للسطر التالي
      lineIndex++;
      setTimeout(typeLine, 1000); // تأخير بين السطور
    }
  }

  typeChar();
}

// بدء تأثير الكتابة عند تحميل الصفحة
window.addEventListener("load", typeLine);
